// // This module decrements a 2-bit Gray code counter on the positive edge of the clock and resets to the last Gray code (10) when the reset signal is high.
module gray_code_counter (
    input clk,
    input reset,
    output reg [1:0] gray
);

    always @(posedge clk or posedge reset) begin
        if (reset)
            gray <= 2'b00;
        else begin
            case (gray)
                2'b00: gray <= 2'b01;
                2'b01: gray <= 2'b11;
                2'b11: gray <= 2'b10;
                2'b10: gray <= 2'b00;
                default: gray <= 2'b00;
            endcase
        end
    end

endmodule
